#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAX_M 1000000000
#define MAX_Q 20

long long gcd(long long a, long long b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

long long lcm(long long a, long long b) {
    return a * b / gcd(a, b);
}

int main() {
    long long N, M, p, q;
    scanf("%lld %lld %lld %lld", &N, &M, &p, &q);
    long long f[MAX_Q + 1];
    for (int i = 0; i <= q; i++) {
        scanf("%lld", &f[i]);
    }
    long long dp[MAX_M + 1];
    dp[0] = 1;
    long long ans = 0;
    for (long long i = 1; i <= M; i++) {
        for (long long j = 1; j <= N; j++) {
            if (j % i == 0) {
                dp[i] = (dp[i] + dp[i - 1]) % MOD;
            }
        }
        long long x = lcm(i, N);
        long long y = gcd(i, N);
        long long value = 0;
        for (int j = 0; j <= q; j++) {
            value = (value + f[j] * (x % MOD) * (y % MOD)) % MOD;
        }
        ans = (ans + value * dp[i]) % MOD;
    }
    printf("%lld\n", ans);
    return 0;
}

